export type OrderState =
  | "PENDING"
  | "CONFIRMED"
  | "SHIPPED"
  | "DELIVERED"
  | "CANCELLED";

// AC1: Valid transitions map
const VALID_TRANSITIONS: Record<OrderState, ReadonlySet<OrderState>> = {
  PENDING: new Set(["CONFIRMED", "CANCELLED"]),
  CONFIRMED: new Set(["SHIPPED", "CANCELLED"]),
  SHIPPED: new Set(["DELIVERED"]),
  DELIVERED: new Set(), // AC4: terminal state
  CANCELLED: new Set(), // AC3: terminal state
};

export class InvalidTransitionError extends Error {
  readonly code = "INVALID_TRANSITION";

  constructor(from: OrderState, to: OrderState) {
    super(`Cannot transition from ${from} to ${to}`);
    this.name = "InvalidTransitionError";
  }
}

export class OrderStateMachine {
  /**
   * Attempt a state transition.
   * @returns the new state if the transition is valid
   * @throws InvalidTransitionError (with code "INVALID_TRANSITION") for invalid transitions
   */
  transition(currentState: OrderState, targetState: OrderState): OrderState {
    if (!VALID_TRANSITIONS[currentState].has(targetState)) {
      throw new InvalidTransitionError(currentState, targetState);
    }
    return targetState;
  }
}
---
import { OrderStateMachine, InvalidTransitionError, OrderState } from "./orderStateMachine";

const machine = new OrderStateMachine();

// ─── helpers ────────────────────────────────────────────────────────────────

function expectInvalidTransition(from: OrderState, to: OrderState) {
  expect(() => machine.transition(from, to)).toThrow(InvalidTransitionError);
  try {
    machine.transition(from, to);
  } catch (err) {
    expect((err as any).code).toBe("INVALID_TRANSITION");
  }
}

// ─── AC1: Valid transitions ──────────────────────────────────────────────────

describe("AC1: valid transitions", () => {
  it("PENDING -> CONFIRMED", () => expect(machine.transition("PENDING", "CONFIRMED")).toBe("CONFIRMED"));
  it("CONFIRMED -> SHIPPED",  () => expect(machine.transition("CONFIRMED", "SHIPPED")).toBe("SHIPPED"));
  it("SHIPPED -> DELIVERED",  () => expect(machine.transition("SHIPPED", "DELIVERED")).toBe("DELIVERED"));
  it("CONFIRMED -> CANCELLED",() => expect(machine.transition("CONFIRMED", "CANCELLED")).toBe("CANCELLED"));
  it("PENDING -> CANCELLED",  () => expect(machine.transition("PENDING", "CANCELLED")).toBe("CANCELLED"));
});

// ─── AC2: Invalid transitions throw INVALID_TRANSITION ───────────────────────

describe("AC2: invalid transitions throw INVALID_TRANSITION", () => {
  it("DELIVERED -> SHIPPED (terminal)",  () => expectInvalidTransition("DELIVERED", "SHIPPED"));
  it("SHIPPED -> PENDING (backward)",    () => expectInvalidTransition("SHIPPED",   "PENDING"));
  it("PENDING -> SHIPPED (skip-a-step)", () => expectInvalidTransition("PENDING",   "SHIPPED"));
  it("PENDING -> DELIVERED (skip-a-step)",() => expectInvalidTransition("PENDING",  "DELIVERED"));
  it("CONFIRMED -> PENDING (backward)",  () => expectInvalidTransition("CONFIRMED", "PENDING"));
  it("SHIPPED -> CONFIRMED (backward)",  () => expectInvalidTransition("SHIPPED",   "CONFIRMED"));
});

// ─── AC3: CANCELLED is a terminal state ──────────────────────────────────────

describe("AC3: CANCELLED cannot transition to any state", () => {
  const allStates: OrderState[] = ["PENDING", "CONFIRMED", "SHIPPED", "DELIVERED", "CANCELLED"];
  for (const target of allStates) {
    it(`CANCELLED -> ${target}`, () => expectInvalidTransition("CANCELLED", target));
  }
});

// ─── AC4: DELIVERED is a terminal state ──────────────────────────────────────

describe("AC4: DELIVERED cannot transition to any state", () => {
  const allStates: OrderState[] = ["PENDING", "CONFIRMED", "SHIPPED", "DELIVERED", "CANCELLED"];
  for (const target of allStates) {
    it(`DELIVERED -> ${target}`, () => expectInvalidTransition("DELIVERED", target));
  }
});

// ─── AC5: PENDING -> CONFIRMED returns CONFIRMED ─────────────────────────────

describe("AC5: PENDING -> CONFIRMED returns CONFIRMED", () => {
  it("returns the new state", () => {
    expect(machine.transition("PENDING", "CONFIRMED")).toBe("CONFIRMED");
  });
});

// ─── AC6: SHIPPED -> PENDING throws INVALID_TRANSITION ───────────────────────

describe("AC6: SHIPPED -> PENDING throws INVALID_TRANSITION", () => {
  it("throws InvalidTransitionError with code INVALID_TRANSITION", () => {
    expectInvalidTransition("SHIPPED", "PENDING");
  });
});

// ─── Error shape ─────────────────────────────────────────────────────────────

describe("Error shape: code, message, instanceof", () => {
  it("is an instanceof InvalidTransitionError and Error, with correct code and message", () => {
    expect(() => machine.transition("SHIPPED", "PENDING")).toThrow(InvalidTransitionError);
    try {
      machine.transition("SHIPPED", "PENDING");
    } catch (err: unknown) {
      expect(err).toBeInstanceOf(InvalidTransitionError);
      expect(err).toBeInstanceOf(Error);
      expect((err as any).code).toBe("INVALID_TRANSITION");
      expect((err as Error).message).toContain("SHIPPED");
      expect((err as Error).message).toContain("PENDING");
    }
  });
});

